const input = $input.first().json;
const action = input.action || 'create_backup';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const BRIDGE_URL = 'http://file-bridge:3200';

const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

const TABLE_DEFS = {
  soul:                 { select: 'key,content', deleteFilter: 'key=neq.', order: 'key' },
  agents:               { select: 'key,content', deleteFilter: 'key=neq.', order: 'key' },
  user_profiles:        { select: 'user_id,name,display_name,timezone,preferences,context,setup_done,setup_step', deleteFilter: 'user_id=neq.', order: 'user_id' },
  tools_config:         { select: 'tool_name,config,enabled', deleteFilter: 'tool_name=neq.', order: 'tool_name' },
  projects:             { select: 'name,status,content', deleteFilter: 'name=neq.', order: 'name' },
  mcp_registry:         { select: 'server_name,path,mcp_url,description,tools,workflow_id,sub_workflow_id,template_id,template_type,active', deleteFilter: 'path=neq.', order: 'created_at.desc' },
  template_credentials: { select: 'template_id,cred_key,cred_value', deleteFilter: 'template_id=neq.', order: 'template_id' },
  memory_long:          { select: 'content,category,importance,embedding,metadata,created_at,updated_at,expires_at', deleteFilter: 'id=gt.0', order: 'created_at.desc' },
  memory_daily:         { select: 'date,content,role,user_id,metadata,created_at', deleteFilter: 'id=gt.0', order: 'created_at.desc' },
  conversations:        { select: 'session_id,user_id,role,content,metadata,created_at', deleteFilter: 'id=gt.0', order: 'created_at.desc' },
  reminders:            { select: 'user_id,chat_id,message,remind_at,type', deleteFilter: 'id=gt.0', filter: 'reminded_at=is.null', order: 'remind_at.desc' },
  scheduled_actions:    { select: 'user_id,chat_id,name,action_type,instruction,schedule,timezone,enabled,notify_mode,metadata', deleteFilter: 'id=gt.0', order: 'created_at.desc' },
  heartbeat_config:     { select: 'check_name,config,interval_minutes,enabled', deleteFilter: 'check_name=neq.', order: 'check_name' },
  tasks:                { select: 'user_id,title,description,status,priority,due_date,tags,metadata', deleteFilter: 'id=gt.0', order: 'created_at.desc' }
};

const SCOPES = {
  core: ['soul', 'agents', 'user_profiles', 'tools_config', 'projects'],
  full: ['soul', 'agents', 'user_profiles', 'tools_config', 'projects', 'mcp_registry', 'template_credentials', 'memory_long', 'memory_daily', 'conversations', 'reminders', 'scheduled_actions', 'heartbeat_config', 'tasks']
};

// Tables with UNIQUE constraints (upsert works)
const UPSERT_TABLES = ['soul', 'agents', 'user_profiles', 'tools_config', 'projects', 'mcp_registry', 'template_credentials', 'heartbeat_config'];

function getTableList(scope, tablesParam) {
  if (scope === 'custom' && tablesParam) {
    const requested = tablesParam.split(',').map(t => t.trim()).filter(t => TABLE_DEFS[t]);
    if (requested.length === 0) {
      return { error: 'No valid table names provided. Available: ' + Object.keys(TABLE_DEFS).join(', ') };
    }
    return { tables: requested };
  }
  return { tables: SCOPES[scope] || SCOPES.full };
}

function formatSize(bytes) {
  if (bytes >= 1048576) return (bytes / 1048576).toFixed(1) + ' MB';
  if (bytes >= 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return bytes + ' B';
}

// === create_backup ===
if (action === 'create_backup') {
  const scope = input.scope || 'full';
  const tableResult = getTableList(scope, input.tables);
  if (tableResult.error) return [{ json: { error: tableResult.error } }];
  const tableList = tableResult.tables;

  const now = new Date();
  const ts = now.toISOString().replace(/[T:]/g, '-').substring(0, 16);
  const fileName = (input.name || 'n8n-claw-backup-' + ts) + '.json';

  const backupData = {};
  const rowCounts = {};

  for (const table of tableList) {
    const def = TABLE_DEFS[table];
    try {
      let url = SUPABASE_URL + '/rest/v1/' + table + '?select=' + def.select;
      if (def.filter) url += '&' + def.filter;
      if (def.order) url += '&order=' + def.order;
      const rows = await helpers.httpRequest({
        method: 'GET',
        url: url,
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
      });
      backupData[table] = rows || [];
      rowCounts[table] = (rows || []).length;
    } catch (err) {
      backupData[table] = [];
      rowCounts[table] = 0;
    }
  }

  const backup = {
    version: '1.0',
    created: now.toISOString(),
    scope: scope,
    tables: backupData
  };

  const jsonStr = JSON.stringify(backup, null, 2);
  const b64 = Buffer.from(jsonStr, 'utf8').toString('base64');

  try {
    const stored = await helpers.httpRequest({
      method: 'POST',
      url: BRIDGE_URL + '/upload/base64',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        content_base64: b64,
        file_name: fileName,
        mime_type: 'application/json'
      })
    });

    const downloadUrl = BRIDGE_URL + '/files/' + stored.id;
    const totalRows = Object.values(rowCounts).reduce((a, b) => a + b, 0);

    let result = 'Backup created: **' + fileName + '**\n';
    result += 'Scope: ' + scope + '\n';
    result += 'Size: ' + formatSize(jsonStr.length) + '\n';
    result += 'Total rows: ' + totalRows + '\n\n';
    result += 'Tables backed up:\n';
    for (const [t, count] of Object.entries(rowCounts)) {
      result += '- ' + t + ': ' + count + ' rows\n';
    }
    result += '\nDownload: ' + downloadUrl + '\n';
    result += '\n[send_file: ' + downloadUrl + ']';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to store backup file: ' + err.message } }];
  }

// === show_backup ===
} else if (action === 'show_backup') {
  const url = input.url;
  if (!url) return [{ json: { error: 'Parameter "url" is required (URL to the backup JSON file).' } }];

  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: url, json: false });
    const backup = typeof resp === 'string' ? JSON.parse(resp) : resp;

    if (!backup.tables || !backup.version) {
      return [{ json: { error: 'Invalid backup file format. Expected version and tables fields.' } }];
    }

    if (input.table) {
      const tableData = backup.tables[input.table];
      if (!tableData) {
        return [{ json: { error: 'Table "' + input.table + '" not found in backup. Available: ' + Object.keys(backup.tables).join(', ') } }];
      }
      let content = JSON.stringify(tableData, null, 2);
      if (content.length > 5000) {
        content = content.substring(0, 5000) + '\n\n... (truncated, ' + content.length + ' chars total, ' + tableData.length + ' rows)';
      }
      return [{ json: { result: '**' + input.table + '** (' + tableData.length + ' rows):\n\n```json\n' + content + '\n```' } }];
    }

    let result = '**Backup Overview**\n';
    result += 'Version: ' + backup.version + '\n';
    result += 'Created: ' + backup.created + '\n';
    result += 'Scope: ' + (backup.scope || 'unknown') + '\n\n';
    result += 'Tables:\n';

    let totalRows = 0;
    for (const [table, rows] of Object.entries(backup.tables)) {
      const count = Array.isArray(rows) ? rows.length : 0;
      totalRows += count;
      result += '- **' + table + '**: ' + count + ' rows\n';
    }
    result += '\nTotal: ' + totalRows + ' rows across ' + Object.keys(backup.tables).length + ' tables\n';
    result += '\nUse show_backup with a specific table name to see its contents.';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to load backup: ' + err.message } }];
  }

// === restore_backup ===
} else if (action === 'restore_backup') {
  const url = input.url;
  if (!url) return [{ json: { error: 'Parameter "url" is required (URL to the backup JSON file).' } }];

  const mode = input.mode || 'upsert';
  if (mode !== 'upsert' && mode !== 'replace') {
    return [{ json: { error: 'Invalid mode "' + mode + '". Use "upsert" (default, merges data) or "replace" (deletes existing data first).' } }];
  }

  let backup;
  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: url, json: false });
    backup = typeof resp === 'string' ? JSON.parse(resp) : resp;
    if (!backup.tables || !backup.version) {
      return [{ json: { error: 'Invalid backup file format.' } }];
    }
  } catch (err) {
    return [{ json: { error: 'Failed to load backup: ' + err.message } }];
  }

  // Determine which tables to restore
  let targetTables = Object.keys(backup.tables);
  if (input.tables) {
    targetTables = input.tables.split(',').map(t => t.trim()).filter(t => backup.tables[t]);
    if (targetTables.length === 0) {
      return [{ json: { error: 'None of the specified tables found in backup. Available: ' + Object.keys(backup.tables).join(', ') } }];
    }
  }

  // Skip sensitive tables unless explicitly requested
  if (input.include_credentials !== 'true') {
    targetTables = targetTables.filter(t => t !== 'template_credentials' && t !== 'tools_config');
  }

  const results = [];
  const warnings = [];

  for (const table of targetTables) {
    const rows = backup.tables[table];
    if (!rows || rows.length === 0) {
      results.push(table + ': 0 rows (skipped, empty)');
      continue;
    }

    const def = TABLE_DEFS[table];
    if (!def) {
      warnings.push(table + ': unknown table, skipped');
      continue;
    }

    try {
      // Replace mode: delete existing data first
      if (mode === 'replace') {
        await helpers.httpRequest({
          method: 'DELETE',
          url: SUPABASE_URL + '/rest/v1/' + table + '?' + def.deleteFilter,
          headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'return=minimal' }
        });
      }

      // Insert/upsert rows in batches of 500
      const batchSize = 500;
      let restored = 0;
      for (let i = 0; i < rows.length; i += batchSize) {
        const batch = rows.slice(i, i + batchSize);
        const headers = {
          'apikey': SUPABASE_KEY,
          'Authorization': 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        };

        // Use upsert for tables with UNIQUE constraints
        if (mode === 'upsert' && UPSERT_TABLES.includes(table)) {
          headers['Prefer'] = 'resolution=merge-duplicates,return=minimal';
        }

        await helpers.httpRequest({
          method: 'POST',
          url: SUPABASE_URL + '/rest/v1/' + table,
          headers: headers,
          body: JSON.stringify(batch)
        });
        restored += batch.length;
      }

      results.push(table + ': ' + restored + ' rows restored');

      // Warn about tables without UNIQUE constraints in upsert mode
      if (mode === 'upsert' && !UPSERT_TABLES.includes(table)) {
        warnings.push(table + ': no unique constraint — rows were inserted (duplicates possible)');
      }
    } catch (err) {
      results.push(table + ': FAILED — ' + err.message);
    }
  }

  let result = '**Restore Complete** (mode: ' + mode + ')\n\n';
  result += 'From backup: ' + backup.created + '\n\n';
  for (const r of results) {
    result += '- ' + r + '\n';
  }

  if (warnings.length > 0) {
    result += '\nWarnings:\n';
    for (const w of warnings) {
      result += '- ' + w + '\n';
    }
  }

  if (input.include_credentials !== 'true' && (backup.tables.template_credentials || backup.tables.tools_config)) {
    result += '\nNote: template_credentials and tools_config were skipped (contain API keys). Use include_credentials=true to restore them.';
  }

  return [{ json: { result } }];

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: create_backup, show_backup, restore_backup.' } }];
}
